import React, { useEffect, useState, useRef } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

export default function UsrProfile() {
  const navigate = useNavigate();
  const [user, setUser] = useState(null);
  const [openMenu, setOpenMenu] = useState(false);

  const menuRef = useRef();

  useEffect(() => {
    const raw = localStorage.getItem("user");
    const stored = raw ? JSON.parse(raw) : null;

    if (!stored?.email) return;

    axios
      .get(`http://localhost:8086/user/profile?email=${stored.email}`)
      .then((res) => setUser(res.data))
      .catch((err) => console.log(err));
  }, []);

  // close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (menuRef.current && !menuRef.current.contains(event.target)) {
        setOpenMenu(false);
      }
    };

    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const handleLogout = () => {
    localStorage.clear();
    navigate("/");
    window.location.reload();
  };

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-indigo-200 via-purple-200 to-pink-200">
        <div className="backdrop-blur-lg bg-white/30 p-6 rounded-xl shadow-lg">
          Loading profile...
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex justify-center items-center bg-gradient-to-br from-indigo-200 via-purple-200 to-pink-200 p-6">

      <div className="backdrop-blur-xl bg-white/30 border border-white/40 shadow-2xl rounded-2xl p-8 w-full max-w-md">

        {/* PROFILE HEADER */}
        <div className="text-center relative">

          <img
            src={
              user.profileImage ||
              `https://ui-avatars.com/api/?name=${user.username}`
            }
            className="w-28 h-28 rounded-full mx-auto object-cover border-4 border-white shadow-lg"
            alt="profile"
          />

          <h2 className="text-2xl font-bold mt-4 text-gray-800">
            {user.name}
          </h2>

          <p className="text-gray-600">{user.email}</p>

          <span className="inline-block mt-2 px-3 py-1 text-xs rounded-full bg-indigo-500 text-white shadow">
            {user.role}
          </span>

          {/* ACTION BUTTON */}
          <div className="relative mt-4" ref={menuRef}>
            <button
              onClick={() => setOpenMenu(!openMenu)}
              className="px-4 py-2 bg-white/40 backdrop-blur rounded-lg shadow hover:bg-white/60 transition"
            >
              Profile Actions ⌄
            </button>

            {/* DROPDOWN */}
            {openMenu && (
              <div className="absolute left-1/2 -translate-x-1/2 mt-2 w-48 bg-white rounded-xl shadow-lg overflow-hidden z-50">

                <button
                  onClick={() => {
                    setOpenMenu(false);
                    navigate("/edit-usr-profile");
                  }}
                  className="w-full text-left px-4 py-2 hover:bg-gray-100"
                >
                  Edit Profile
                </button>

                <button
                  onClick={() => {
                    setOpenMenu(false);
                    handleLogout();
                  }}
                  className="w-full text-left px-4 py-2 hover:bg-gray-100 text-red-500"
                >
                  Logout
                </button>

              </div>
            )}
          </div>

        </div>

        {/* DIVIDER */}
        <div className="border-t border-white/40 my-6"></div>

        {/* INFO SECTION */}
        <div className="space-y-3 text-sm">

          <div className="bg-white/20 p-3 rounded-xl flex justify-between">
            <span className="font-semibold">Username</span>
            <span>{user.username}</span>
          </div>

          <div className="bg-white/20 p-3 rounded-xl flex justify-between">
            <span className="font-semibold">Name</span>
            <span>{user.name}</span>
          </div>

          <div className="bg-white/20 p-3 rounded-xl flex justify-between">
            <span className="font-semibold">Role</span>
            <span>{user.role}</span>
          </div>

        </div>

      </div>
    </div>
  );
}
